// Inside an unsafe block, you can:
// 1. Dereference a raw pointer
// 2. Call an unsafe function or method
// 3. Access or modify a mutable static variable
// 4. Implement an unsafe trait
// 5. Access fields of a union

let mut x = 42;
let ptr = &mut x as *mut i32;
unsafe {
    *ptr = 100;
}
assert_eq!(x, 100);

unsafe fn dangerous() {
    // entire body is an unsafe context
}
unsafe {
    dangerous();
}

pub fn split_at_mut(slice: &mut [i32], mid: usize) -> (&mut [i32], &mut [i32]) {
    let len = slice.len();
    let ptr = slice.as_mut_ptr();
    assert!(mid <= len);
    unsafe {
        (
            std::slice::from_raw_parts_mut(ptr, mid),
            std::slice::from_raw_parts_mut(ptr.add(mid), len - mid),
        )
    }
}

let x = 42;
let r: *const i32 = &x;          // immutable raw pointer
let mut y = 42;
let mr: *mut i32 = &mut y;       // mutable raw pointer

let val = 42;
let const_ptr: *const i32 = &val as *const i32;
let mut_val = 42;
let mut_ptr: *mut i32 = &mut mut_val as *mut i32;

let address = 0x012345usize;
let ptr = address as *const i32;
// Dereferencing an arbitrary address is extremely dangerous
// unsafe { println!("{}", *ptr); } // likely segfault

let x = 42;
let ptr = &x as *const i32;
unsafe {
    assert_eq!(*ptr, 42);
}

let ptr: *const i32 = std::ptr::null();
assert!(ptr.is_null());

let x = 42;
let valid_ptr = &x as *const i32;
assert!(!valid_ptr.is_null());

let arr = [10, 20, 30, 40, 50];
let ptr = arr.as_ptr();
unsafe {
    assert_eq!(*ptr, 10);
    assert_eq!(*ptr.add(1), 20);
    assert_eq!(*ptr.add(4), 50);
    // ptr.offset(2) is equivalent to ptr.add(2) for positive offsets
}

// Raw pointers (*const T, *mut T):
// - Can be null
// - No lifetime tracking
// - Multiple *mut to same data allowed
// - No auto-deref
// - Manual memory management

// References (&T, &mut T):
// - Never null
// - Lifetime tracked by compiler
// - Borrowing rules enforced
// - Auto-deref
// - Memory managed by ownership

/// # Safety
/// `ptr` must be a valid pointer to an initialized i32.
unsafe fn read_value(ptr: *const i32) -> i32 {
    *ptr
}

let x = 42;
let ptr = &x as *const i32;
let val = unsafe { read_value(ptr) };

struct Buffer {
    data: *mut u8,
    len: usize,
}
impl Buffer {
    /// # Safety
    /// Index must be within bounds.
    unsafe fn get_unchecked(&self, index: usize) -> u8 {
        *self.data.add(index)
    }
}

// Common unsafe functions in std:
let v = vec![1, 2, 3];
unsafe {
    let val = v.get_unchecked(1);  // no bounds check
}
let s = unsafe { String::from_utf8_unchecked(vec![104, 105]) };

static mut COUNTER: u32 = 0;

fn increment() {
    unsafe {
        COUNTER += 1;
    }
}
fn get_count() -> u32 {
    unsafe { COUNTER }
}

use std::sync::atomic::{AtomicU32, Ordering};
static COUNTER: AtomicU32 = AtomicU32::new(0);

fn increment() {
    COUNTER.fetch_add(1, Ordering::SeqCst);
}
fn get_count() -> u32 {
    COUNTER.load(Ordering::SeqCst)
}

use std::sync::OnceLock;
static CONFIG: OnceLock<String> = OnceLock::new();

fn init_config(value: String) {
    CONFIG.set(value).ok();
}
fn get_config() -> &'static str {
    CONFIG.get().map(|s| s.as_str()).unwrap_or("default")
}

/// # Safety
/// Implementors must ensure that `validate()` always
/// returns true for valid instances.
unsafe trait Validate {
    fn validate(&self) -> bool;
}

struct PositiveInt(i32);

unsafe impl Validate for PositiveInt {
    fn validate(&self) -> bool {
        self.0 > 0
    }
}

struct MyWrapper(*mut u8);

// We guarantee MyWrapper is safe to send between threads
unsafe impl Send for MyWrapper {}

// We guarantee &MyWrapper is safe to share between threads
unsafe impl Sync for MyWrapper {}

use std::alloc::{GlobalAlloc, Layout};

struct MyAllocator;

unsafe impl GlobalAlloc for MyAllocator {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        std::alloc::System.alloc(layout)
    }
    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        std::alloc::System.dealloc(ptr, layout)
    }
}

#[global_allocator]
static ALLOC: MyAllocator = MyAllocator;

extern "C" {
    fn abs(input: i32) -> i32;
    fn strlen(s: *const std::ffi::c_char) -> usize;
}

let result = unsafe { abs(-42) };
assert_eq!(result, 42);

#[no_mangle]
pub extern "C" fn rust_add(a: i32, b: i32) -> i32 {
    a + b
}

use std::ffi::{CString, CStr};

// Rust -> C string
let c_string = CString::new("hello").unwrap();
let ptr = c_string.as_ptr();

// C string -> Rust
let c_str = unsafe { CStr::from_ptr(ptr) };
let rust_str = c_str.to_str().unwrap();

// Represent a C struct we don't know the layout of:
#[repr(C)]
pub struct OpaqueHandle {
    _private: [u8; 0],
}

extern "C" {
    fn create_handle() -> *mut OpaqueHandle;
    fn destroy_handle(h: *mut OpaqueHandle);
    fn use_handle(h: *const OpaqueHandle) -> i32;
}

#[repr(C)]
struct Point {
    x: f64,
    y: f64,
}

extern "C" {
    fn distance(p1: *const Point, p2: *const Point) -> f64;
}

extern "C" {
    fn register_callback(cb: extern "C" fn(i32));
}

extern "C" fn my_callback(value: i32) {
    println!("callback called with: {value}");
}

unsafe {
    register_callback(my_callback);
}

#[repr(C)]
union IntOrFloat {
    i: i32,
    f: f32,
}

let u = IntOrFloat { i: 42 };
unsafe {
    println!("as int: {}", u.i);
    println!("as float: {}", u.f); // reinterprets bits
}

use std::mem::ManuallyDrop;

union MyUnion {
    num: i32,
    text: ManuallyDrop<String>,
}

let u = MyUnion { num: 42 };
// Drop is not automatically called for union fields

// Instead of transmute for numeric types:
let x: u32 = 42;
let y = f32::from_bits(x);
let z = x.to_ne_bytes();

// Instead of transmute for slices:
let bytes: &[u8] = &[1, 0, 0, 0];
let int = u32::from_ne_bytes(bytes.try_into().unwrap());

use std::pin::Pin;
use std::marker::PhantomPinned;

struct SelfRef {
    data: String,
    ptr: *const String,
    _pin: PhantomPinned,
}

impl SelfRef {
    fn new(data: String) -> Pin<Box<Self>> {
        let mut boxed = Box::pin(SelfRef {
            data,
            ptr: std::ptr::null(),
            _pin: PhantomPinned,
        });
        let ptr = &boxed.data as *const String;
        unsafe {
            let mut_ref = Pin::as_mut(&mut boxed);
            Pin::get_unchecked_mut(mut_ref).ptr = ptr;
        }
        boxed
    }
}

use std::arch::asm;

let x: u64;
unsafe {
    asm!("mov {}, 42", out(reg) x);
}
assert_eq!(x, 42);

